ArtalkXmppClient.example:
This example shows how to use the GetFeatures method to print out a
list of features supported by the XMPP client of a chat contact.

  string hostname = "artalk.ir",
    username = "myUsername",
    password = "myPassword";
  Jid juliet = "ammar@artalk.ir/balcony";

  using (var cl = new ArtalkXmppClient(hostname, username, password)) {
    cl.Connect();

    Console.WriteLine("Juliet's XMPP client supports: ");
    foreach (var feat in cl.GetFeatures(juliet))
      Console.WriteLine(" - " + feat);
  }

This example demonstrates how to use the SendMessage method in order
to send a chat-message to a contact.

  string hostname = "artalk.ir",
    username = "myUsername",
    password = "myPassword";
  Jid juliet = "ammar@artalk.ir/balcony";

  using (var cl = new ArtalkXmppClient(hostname, username, password)) {
    cl.Connect();

    while(true) {
      Console.Write("Type a message or type 'quit' to exit: ");
      string s = Console.ReadLine();
      if(s == "quit")
        return;
      // Send the message to Juliet.
      cl.SendMessage(juliet, s);
    }
}

This example demonstrates how to use the SendMessage method in order
to send a multi-language chat-message to a contact.

  string hostname = "artalk.ir",
    username = "myUsername",
    password = "myPassword";
  Jid juliet = "ammar@artalk.ir/balcony";

  using (var cl = new ArtalkXmppClient(hostname, username, password)) {
    cl.Connect();

    cl.SendMessage(juliet, new Dictionary<string, string>() {
      { "en", "Hi, how are you?" },
      { "dk", "Hej, hvordan har du det?" },
      { "de", "Hallo, wie geht es dir?" },
      { "jp", "お元気ですか?" }
    });
  }

This example demonstrates how to use the GetRoster method in order
to retrieve a list of all of the user's contacts.

  string hostname = "artalk.ir",
    username = "myUsername",
    password = "myPassword";

  using (var cl = new ArtalkXmppClient(hostname, username, password)) {
    cl.Connect();

    Console.WriteLine("Contacts on " + cl.Jid.Node + "'s contact-list:");
    foreach (var item in cl.GetRoster())
      Console.WriteLine(" - " + item.Jid);
  }

This example demonstrates RFC 7622-oriented JID normalization.
Jid jid = "USER@XN--BCHER-KVA.Example./Phone";
Console.WriteLine(jid.Node); // user Console.WriteLine(jid.Domain); // bücher.example Console.WriteLine(jid.Resource); // Phone Console.WriteLine(jid); // user@bücher.example/Phone

This example demonstrates how to connect to a server that expects TLS
immediately after the TCP connection is established.

  string hostname = "artalk.ir",
    username = "myUsername",
    password = "myPassword";

  using (var cl = new ArtalkXmppClient(hostname, username, password,
    port: 5223, directTls: true)) {
    cl.Connect("direct-tls-client");
  }

This example demonstrates how to connect through an XMPP BOSH
connection manager.

  Uri boshUrl = new Uri("https://chat.artalk.ir/http-bind");
  string hostname = "artalk.ir",
    username = "myUsername",
    password = "myPassword";

  using (var cl = new ArtalkXmppClient(boshUrl, hostname, username,
    password)) {
    cl.Connect("bosh-client");
    cl.SendMessage("ammar@artalk.ir", "Hello over BOSH");
  }

This example demonstrates how to connect through an RFC 7395 XMPP
WebSocket endpoint.

  Uri webSocketUrl = new Uri("wss://chat.artalk.ir/xmpp-websocket");
  string hostname = "artalk.ir",
    username = "myUsername",
    password = "myPassword";

  using (var cl = new ArtalkXmppClient(webSocketUrl, hostname,
    username, password, XmppTransportBinding.WebSocket)) {
    cl.Connect("websocket-client");
    cl.SendMessage("ammar@artalk.ir", "Hello over WebSocket");
  }

This example demonstrates how to authenticate with a server that
advertises the SASL OAUTHBEARER mechanism.

  string hostname = "artalk.ir",
    username = "myUsername",
    accessToken = "OAuthAccessToken";

  using (var cl = new ArtalkXmppClient(hostname)) {
    cl.Username = username;
    cl.OAuthBearerToken = accessToken;
    cl.Connect("oauth-client");
  }

This example demonstrates how to authenticate with a Cisco Jabber
deployment that advertises the SASL CISCO-VTG-TOKEN mechanism.

  string hostname = "cisco-im.example.com",
    username = "user@example.com",
    ciscoToken = "CiscoVtgToken";

  using (var cl = new ArtalkXmppClient(hostname)) {
    cl.Username = username;
    cl.CiscoVtgToken = ciscoToken;
    cl.Connect("jabber-client");
  }

This example demonstrates how to publish OMEMO device metadata and
send an encrypted OMEMO message through a pluggable OMEMO session
cipher.

  string hostname = "artalk.ir",
    username = "myUsername",
    password = "myPassword";
  uint deviceId = 123456;

  using (var cl = new ArtalkXmppClient(hostname, username, password)) {
    cl.OmemoDeviceListChanged += (sender, e) => {
      Console.WriteLine(e.Jid + " devices: " +
        String.Join(", ", e.DeviceList.DeviceIds));
    };

    cl.Connect("omemo-device");
    cl.PublishOmemoDeviceList(new uint[] { deviceId });

    var bundle = new OmemoBundle(
      signedPreKeyId: 1,
      signedPreKey: signedPreKeyPublicBytes,
      signedPreKeySignature: signedPreKeySignatureBytes,
      identityKey: identityKeyBytes,
      preKeys: new Dictionary<uint, byte[]> {
        { 1, preKeyPublicBytes }
      });

    cl.PublishOmemoBundle(deviceId, bundle);

    IOmemoSessionCipher sessionCipher = CreateSignalProtocolAdapter();
    var trustStore = new MemoryOmemoTrustStore();
    trustStore.SetTrust("ammar@artalk.ir", 654321,
      recipientIdentityKeyBytes, OmemoTrustLevel.Trusted);

    byte[] plaintext = Encoding.UTF8.GetBytes("hello");
    cl.SendOmemoMessage("ammar@artalk.ir", plaintext, deviceId,
      sessionCipher, trustStore);
  }

This example demonstrates how to prepare an XEP-0454 OMEMO media
sharing body after encrypting a file for HTTP upload.

  Uri uploadUrl = new Uri("https://upload.artalk.ir/files/photo.jpg");
  byte[] fileBytes = File.ReadAllBytes("photo.jpg");

  OmemoMediaUri mediaUri = OmemoMediaUri.Create(uploadUrl);
  byte[] encryptedFile = mediaUri.Encrypt(fileBytes);
  long encryptedSize = OmemoMediaUri.GetEncryptedLength(fileBytes.LongLength);

  // Request an HTTP upload slot for encryptedSize bytes and upload
  // encryptedFile to uploadUrl before sending the OMEMO body.
  string body = new OmemoMediaMessage(mediaUri).ToString();

  cl.SendOmemoMessage("ammar@artalk.ir",
    Encoding.UTF8.GetBytes(body), deviceId, sessionCipher, trustStore);

This example demonstrates how to track contact presence updates.

  string hostname = "artalk.ir",
    username = "myUsername",
    password = "myPassword";

  using (var cl = new ArtalkXmppClient(hostname, username, password)) {
    cl.StatusChanged += (sender, e) => {
      Console.WriteLine(e.Jid + ": " + e.Status.Availability);
    };

    cl.Connect("presence-sample");
    cl.SetStatus(Availability.Online, "Ready");
    Console.ReadLine();
  }

This example demonstrates how to join a multi-user chat room and
receive groupchat messages.

  string hostname = "artalk.ir",
    username = "myUsername",
    password = "myPassword";
  Jid room = "room@conference.artalk.ir";

  using (var cl = new ArtalkXmppClient(hostname, username, password)) {
    cl.RoomMessage += (sender, e) => {
      Console.WriteLine("[" + e.RoomJid + "] " +
        e.Nickname + ": " + e.Message.Body);
    };

    cl.RoomPresence += (sender, e) => {
      Console.WriteLine(e.Occupant.Nickname + " available: " +
        e.IsAvailable);
    };

    cl.Connect("muc-sample");
    cl.JoinRoom(room, "myNickname");
    cl.SendRoomMessage(room, "Hello room");
    Console.ReadLine();
    cl.LeaveRoom(room, "myNickname");
  }

This example demonstrates how to enable automatic server pings for a
long-running client connection.

  string hostname = "artalk.ir",
    username = "myUsername",
    password = "myPassword";

  using (var cl = new ArtalkXmppClient(hostname, username, password)) {
    cl.KeepAliveInterval = TimeSpan.FromMinutes(5);
    cl.KeepAliveTimeout = TimeSpan.FromSeconds(15);
    cl.KeepAliveFailed += (sender, e) => {
      Console.WriteLine("Keepalive failed: " + e.Exception.Message);
    };
    cl.Error += (sender, e) => {
      Console.WriteLine(e.Exception);
    };
    cl.Disconnected += (sender, e) => {
      Console.WriteLine("Disconnected");
    };

    cl.Connect("long-running-client");
    Console.ReadLine();
  }

This example demonstrates how to register a new account with a server
that supports in-band registration.

  string hostname = "artalk.ir";

  using (var cl = new ArtalkXmppClient(hostname)) {
    cl.Connect();
    cl.Register(form => new SubmitForm(
      new TextField("username", "myNewUsername"),
      new PasswordField("password", "myNewPassword")));
  }

This example demonstrates how to use the SetTune method in order
to publish tune information to other contacts.

    string hostname = "artalk.ir",
      username = "myUsername",
      password = "myPassword";

    using (var cl = new ArtalkXmppClient(hostname, username, password)) {
      cl.Connect();

      // Let your contacts know what you are currently listening to.
      cl.SetTune(new TuneInformation("Every Breath You Take", "The Police"));

      Console.WriteLine("Type 'quit' to exit.");
      while(Console.ReadLine() != "quit");
  }

This example demonstrates how to use the SetActivity method in order
to publish the user's current activity.

    string hostname = "artalk.ir",
      username = "myUsername",
      password = "myPassword";

    using (var cl = new ArtalkXmppClient(hostname, username, password)) {
      cl.Connect();

      // Let your contacts know what you are currently doing.
      cl.SetActivity(GeneralActivity.Eating, SpecificActivity.HavingBreakfast);

      Console.WriteLine("Type 'quit' to exit.");
      while(Console.ReadLine() != "quit");
  }

This example demonstrates how to set up the SubscriptionRequest delegate in
order to process incoming subscription requests.

  static void Main(string[] args) {
    string hostname = "artalk.ir",
      username = "myUsername",
      password = "myPassword";

    using (var cl = new ArtalkXmppClient(hostname, username, password)) {
      cl.SubscriptionRequest = OnSubscriptionRequest;
      cl.Connect();

      // Put the thread to sleep and wait for subscription requests.
      Thread.Sleep(Timeout.Infinite);
    }
  }

  /// <summary>
  /// A callback method that is invoked whenever a subscription request from
  /// another XMPP user is received.
  /// </summary>
  /// <param name="from">The JID of the XMPP user who wishes to subscribe to our
  /// presence.</param>
  /// <returns>true to approve the request; Otherwise false.</returns>
  static bool OnSubscriptionRequest(Jid from) {
    Console.WriteLine(from + " wants to subscribe to your presence.");
    Console.Write("Type Y to approve the request, or any other key to refuse it: ");

    // Return true to approve the request, or false to refuse it.
    return Console.ReadLine().ToLowerInvariant() == "y";
  }
